import { precacheAndRoute } from 'workbox-precaching'
import { registerRoute } from 'workbox-routing'
import { NetworkFirst } from 'workbox-strategies'

// Precache all of the assets generated by your build process.
precacheAndRoute(self.__WB_MANIFEST)

// Set up App Shell-style routing in the SW to return a shell for navigation requests.
registerRoute(
  // Return false to exempt requests from being fulfilled by index.html.
  ({ request }) => request.mode === 'navigate',
  ({ url }) => fetch(url.href).catch(() => caches.match('/'))
)

// Cache API requests with NetworkFirst strategy
registerRoute(
  /^https:\/\/api\.eduvizion\.com\/.*/i,
  new NetworkFirst({
    cacheName: 'api-cache',
    plugins: [
      {
        cacheWillUpdate: async ({ response }) => {
          // Ensure we only cache valid responses
          if (response.status === 200) {
            return response
          }
          return null
        }
      }
    ]
  })
)

// Cache images with CacheFirst strategy
registerRoute(
  ({ request }) => request.destination === 'image',
  new CacheFirst({
    cacheName: 'image-cache',
    plugins: [
      {
        cacheWillUpdate: async ({ response }) => {
          if (response.status === 200) {
            return response
          }
          return null
        }
      }
    ]
  })
)